print(f"{(num1 := int(input('Insira o primeiro valor inteiro: '))) and ''}{(num2 := int(input('Insira o segundo valor inteiro: '))) and ''}{(resto := num1 % num2) and ''}{(f'A soma dos números mais o resto da divisão é {num1 + num2 + resto}.' if resto == 1 else (f'O primeiro valor é {"par" if num1 % 2 == 0 else "ímpar"} e o segundo valor é {"par" if num2 % 2 == 0 else "ímpar"}.' if resto == 2 else (f'O resultado da multiplicação da soma dos valores pelo primeiro é {(num1 + num2) * num1}.' if resto == 3 else (f'O resultado da divisão da soma dos valores pelo segundo é {(num1 + num2) / num2}.' if resto == 4 and num2 != 0 else ('O resultado da divisão da soma dos valores pelo segundo é infinito.' if resto == 4 and num2 == 0 else f'O quadrado do primeiro valor é {num1 ** 2} e o quadrado do segundo valor é {num2 ** 2}.')))))}")
